        if (syscall_no as isize) < 0 {
            log::error!("wrong syscall id? {}", syscall_no as isize);
            return -(SysError::ENOSYS.code() as isize) as usize;
        }

        print!(
            "Syscall number not included: {syscall_no} | {}",
            syscall_no as isize
        );
