/// handle exception or interrupt from a task, return if success.
/// __trap_from_user saved TrapContext, then jump to
/// the middle of trap_return(), and then return to
/// task_executor_unit(), which calls this trap_handler() function.
pub fn trap_handler(task: &Task) {
    let stval = register::stval::read();
    let sepc = register::sepc::read();
    let cause = register::scause::read().cause();

    unsafe { load_trap_handler() };

    // Here task updates global timer manager and checks if there
    // are any expired timer. If there is, the task will wake up
    // the relevant thread.
    // to ensure that timer check is stably called, the kernel
    // spawns a timer kernel thread [`time_init`] to do this.
    let current = get_time_duration();
    TIMER_MANAGER.check(current);

    match cause {
        Trap::Exception(e) => {
            user_exception_handler(task, Exception::from_number(e).unwrap(), stval, sepc)
        }
        Trap::Interrupt(i) => user_interrupt_handler(task, Interrupt::from_number(i).unwrap()),
    }
}

pub fn user_exception_handler(task: &Task, e: Exception, stval: usize, sepc: usize) {
    match e {
        Exception::UserEnvCall => {
            task.set_is_syscall(true);
        }
        Exception::StorePageFault | Exception::InstructionPageFault | Exception::LoadPageFault => {
            let access = match e {
                Exception::InstructionPageFault => MappingFlags::X,
                Exception::LoadPageFault => MappingFlags::R,
                Exception::StorePageFault => MappingFlags::W,
                _ => unreachable!(),
            };
            let fault_addr = VirtAddr::new(stval);
            let addr_space = task.addr_space();
            if let Err(e) = addr_space.handle_page_fault(fault_addr, access) {
                log::error!(
                    "[user_exception_handler] task [{}] {} unsolved page fault at {:#x}, \
                    access: {:?}, error: {:?}, bad instruction at {:#x}",
                    task.tid(),
                    task.get_name(),
                    fault_addr.to_usize(),
                    access,
                    e.as_str(),
                    sepc
                );
                task.receive_siginfo(SigInfo {
                    sig: Sig::SIGSEGV,
                    code: SigInfo::USER,
                    details: SigDetails::Kill {
                        pid: task.get_pgid(),
                        siginfo: None,
                    },
                });
            }
        }
        Exception::IllegalInstruction => {
            log::error!(
                "[trap_handler] illegal instruction {:#x} at {:#x}",
                stval,
                sepc
            );
            task.receive_siginfo(SigInfo {
                sig: Sig::SIGILL,
                code: SigInfo::USER,
                details: SigDetails::Kill {
                    pid: task.get_pgid(),
                    siginfo: None,
                },
            });
        }
        e => {
            log::error!("Unknown user exception: {:?}", e);
        }
    }
}

pub fn user_interrupt_handler(task: &Task, i: Interrupt) {
    // log::error!("interrupt! {:?}", i);
    match i {
        Interrupt::SupervisorTimer => {
            set_nx_timer_irq();
            TRAP_STATS.inc(i.number());
        }
        Interrupt::SupervisorExternal => {
            log::error!("[user] receive externel interrupt");
            device_manager().handle_irq();
            TRAP_STATS.inc(i.number());
        }
        _ => {
            panic!("[trap_handler] Unsupported interrupt {:?}", i);
        }
    }
}

#![no_std]
#![no_main]

extern crate alloc;

use alloc::collections::VecDeque;
use async_task::{Runnable, ScheduleInfo, Task, WithInfo};
use lazy_static::lazy_static;
use mutex::SpinNoIrqLock;

use config::device::MAX_HARTS;

const HART_TASKS_LINE: TaskLine = TaskLine::new();
pub static mut HART_TASKS_LINES: [TaskLine; MAX_HARTS] = [HART_TASKS_LINE; MAX_HARTS];
pub static mut HART_RUN_MASK: usize = 0;

lazy_static! {
    static ref TASKLINE: TaskLine = TaskLine::new();
}

/// Task Line
///
/// Tasks in line is the runnable for async schedule.
/// Used to take control of async tasks.
#[derive(Debug)]
pub struct TaskLine {
    tasks: SpinNoIrqLock<VecDeque<Runnable>>,
    pritasks: SpinNoIrqLock<VecDeque<Runnable>>,
}

impl TaskLine {
    pub const fn new() -> Self {
        Self {
            tasks: SpinNoIrqLock::new(VecDeque::new()),
            pritasks: SpinNoIrqLock::new(VecDeque::new()),
        }
    }

    pub fn push(&self, task: Runnable) {
        self.tasks.lock().push_back(task);
    }

    pub fn push_prio(&self, task: Runnable) {
        self.pritasks.lock().push_back(task);
    }

    pub fn fetch(&self) -> Option<Runnable> {
        if let Some(task) = self.fetch_prio() {
            return Some(task);
        }
        self.tasks.lock().pop_front()
    }

    pub fn fetch_prio(&self) -> Option<Runnable> {
        self.pritasks.lock().pop_front()
    }

    pub fn length(&self) -> usize {
        self.tasks.lock().len() + self.pritasks.lock().len()
    }
}

#[allow(static_mut_refs)]
pub fn push_in_available_line(runnable: Runnable, info: ScheduleInfo) {
    // log::trace!("One Task is Waken!");
    let mut least_waiting_tasks_num: usize = usize::MAX;
    let mut available_line_id: usize = 0;

    if MAX_HARTS == 1 {
        available_line_id = 0;
        unsafe {
            if info.woken_while_running {
                HART_TASKS_LINES[available_line_id].push(runnable);
            } else {
                HART_TASKS_LINES[available_line_id].push_prio(runnable);
            }
        }
        return;
    }

    for i in 0..MAX_HARTS {
        let hart_mask = 1 << i;
        unsafe {
            if (hart_mask & HART_RUN_MASK) != 0 {
                let waiting_num = HART_TASKS_LINES[i].length();
                if waiting_num < least_waiting_tasks_num {
                    least_waiting_tasks_num = waiting_num;
                    available_line_id = i;
                }
            }
        }
    }
    // log::debug!("push task into [{}] line", available_line_id);

    unsafe {
        if info.woken_while_running {
            HART_TASKS_LINES[available_line_id].push(runnable);
        } else {
            HART_TASKS_LINES[available_line_id].push_prio(runnable);
        }
    }
}

pub fn spawn<F>(future: F) -> (Runnable, Task<F::Output>)
where
    F: Future + Send + 'static,
    F::Output: Send + 'static,
{
    let schedule = move |runnable: Runnable, info: ScheduleInfo| {
        push_in_available_line(runnable, info);
    };
    let (runnable, handle) = async_task::spawn(future, WithInfo(schedule));
    (runnable, handle)
}

pub fn task_run_always_alone(hart_id: usize) {
    while let Some(task) = fetch_one(hart_id) {
        task.run();
    }
}

pub fn has_waiting_task_alone(hart_id: usize) -> bool {
    unsafe { HART_TASKS_LINES[hart_id].length() > 0 }
}

pub fn task_run_always() {
    while let Some(task) = TASKLINE.fetch() {
        task.run();
    }
}

pub fn task_run_once() {
    if let Some(task) = TASKLINE.fetch() {
        task.run();
    }
}

pub fn has_waiting_task() -> bool {
    TASKLINE.length() > 0
}

pub fn init(hart_id: usize) {
    unsafe {
        HART_RUN_MASK |= 1 << hart_id;
    }
}

pub fn fetch_one(hart_id: usize) -> Option<Runnable> {
    unsafe {
        if let Some(task) = HART_TASKS_LINES[hart_id].fetch() {
            return Some(task);
        }

        for i in 0..MAX_HARTS {
            if i == hart_id {
                continue;
            }
            let hart_mask = 1 << i;
            if (hart_mask & HART_RUN_MASK) != 0 {
                if let Some(task) = HART_TASKS_LINES[i].fetch() {
                    return Some(task);
                }
            }
        }
    }

    None
}

