            vaddr: VirtAddr::new(vaddr),
        })
    }

    pub fn new_key(
        vaddr: usize,
        addrspace: Arc<AddrSpace>,
        is_private: bool,
    ) -> SysResult<FutexHashKey> {
        match is_private {
            true => FutexHashKey::new_private_key(vaddr, addrspace),
            false => FutexHashKey::new_share_key(vaddr, &addrspace),
        }
    }
