                return Err(SysError::ECHILD);
            }
            if let Some(child) = children.get(&pid) {
                if child.is_in_state(TaskState::WaitForRecycle) {
                    Some(child.clone())
                } else {
                    None
                }
            } else {
                log::warn!("[sys_wait4] task {} [{}] wait4 fail at beginning: no child with pid {pid}", task.tid(), task.get_name());
                return Err(SysError::ECHILD);
            }
