pub async fn sig_check(task: Arc<Task>, interrupted: &mut bool) {
    let old_mask = task.get_sig_mask();

    while let Some(si) = task.sig_manager_mut().dequeue_signal(&old_mask) {
        // if sig_exec turns to user handler, it will return true to break the loop and run user handler.
        let ret = sig_exec(task.clone(), si, interrupted).await;

        match ret {
            Ok(b) if b => break,
            Ok(_) => continue,
            Err(e) => {
                log::error!("[sig_check] sig_exec: {:?}", e);
            }
        }
    }
}

async fn sig_exec(task: Arc<Task>, si: SigInfo, interrupted: &mut bool) -> SysResult<bool> {
    let action = task.sig_handlers_mut().lock().get(si.sig);
    let cx = task.trap_context_mut();
    let old_mask = task.get_sig_mask();

    if *interrupted && action.flags.contains(SigActionFlag::SA_RESTART) {
        cx.sepc -= 4;
        cx.restore_last_user_ret_val();
        *interrupted = false;
        log::info!("[sig_exec] restart syscall");
    }

    match action.atype {
        ActionType::Ignore => Ok(false),
        ActionType::Kill => {
            if task.tid() == 1 {
                log::warn!("[sig_exec] kill init task, ignored");
                return Ok(false);
            }
            kill(&task, si.sig);
            Ok(false)
        }
        ActionType::Stop => {
            if task.tid() == 1 {
                log::warn!("[sig_exec] kill init task, ignored");
                return Ok(false);
            }
            stop(&task, si.sig);
            Ok(false)
        }
        ActionType::Cont => {
            cont(&task, si.sig);
            Ok(false)
        }
        ActionType::User { entry } => {
            // The signal being delivered is also added to the signal mask, unless
            // SA_NODEFER was specified when registering the handler.
            if !action.flags.contains(SigActionFlag::SA_NODEFER) {
                task.sig_mask_mut().add_signal(si.sig)
            };
            // 信号定义中可能包含了在处理该信号时需要阻塞的其他信号集。
            // 这些信息定义在Action的mask字段
            *task.sig_mask_mut() |= action.mask;
            // TODO: cx.user_fx.encounter_signal();
            // TODO: sig_stack isn't actually used for now (Even so in Phoenix, because sig_stack is always None)
            // let sig_stack = task.sig_stack_mut().take();
            // let sp = match sig_stack {
            //     Some(s) => {
            //         log::error!("[sigstack] use user defined signal stack. Unimplemented");
            //         s.get_stack_top()
            //     }
            //     None => {
            //         // 如果进程未定义专门的信号栈，
            //         // 用户自定义的信号处理函数将使用进程的普通栈空间，
            //         // 即和其他普通函数相同的栈。这个栈通常就是进程的主栈，
            //         // 也就是在进程启动时由操作系统自动分配的栈。
            //         cx.get_user_sp()
            //     }
            // };

            let sig_stack = task.sig_stack_mut();
            let use_altstack = action.flags.contains(SigActionFlag::SA_ONSTACK)
                && (sig_stack.ss_flags & SS_DISABLE) == 0
                && (sig_stack.ss_flags & SS_ONSTACK) == 0;

            let sp = if use_altstack {
                sig_stack.ss_flags |= SS_ONSTACK;
                sig_stack.get_stack_top()
            } else {
                cx.get_user_sp()
            };

            // extend the sig_stack
            // 在栈上压入一个sig_cx，存储trap frame里的寄存器信息

            let mut new_sp = sp - size_of::<SigContext>();
            let addr_space = task.addr_space();
            let mut sig_cx_ptr = UserWritePtr::<SigContext>::new(new_sp, &addr_space);
            // TODO: should increase the size of the sig_stack? It seems umi doesn't
            let mut sig_cx = SigContext {
                flags: 0,
                link: 0,
                stack: *sig_stack,
                mask: old_mask,
                sig: [0; 16],
                user_reg: cx.user_reg,
                fpstate: [0; 66],
            };
            sig_cx.user_reg[0] = cx.sepc;
            // log::debug!("[sig context] sig_cx_ptr: {sig_cx_ptr:?}");

            unsafe { sig_cx_ptr.write(sig_cx)? };

            // restore the new stack pointer in Task for sigreturn to recover
            task.set_sig_cx_ptr(new_sp);
            // user defined void (*sa_handler)(int);
            cx.set_user_a0(si.sig.raw());

            // if sa_flags contains SA_SIGINFO, It means user defined function is
            // void (*sa_sigaction)(int, siginfo_t *, void *sig_cx); which two more
            // parameters
            // FIXME: `SigInfo` and `SigContext` may not be the exact struct in C, which will
            // cause a random bug that sometimes user will trap into kernel because of
            // accessing kernel addrress
            // FIXME: SA_SIGINFO should be handled in sig_exec by accepting the siginfo_t *
            // and void *sig_cx.
            if action.flags.contains(SigActionFlag::SA_SIGINFO) {
                // log::error!("[SA_SIGINFO] set sig_cx {sig_cx:?}");
                // a2
                cx.set_user_a2(new_sp);

                let siginfo = if let SigDetails::Kill { pid: _, siginfo } = si.details {
                    match siginfo {
                        Some(info) => info,
                        None => {
                            log::warn!("[sig_exec] siginfo is None, use the default value");
                            LinuxSigInfo {
                                si_signo: si.sig.raw() as _,
                                si_code: si.code,
                                si_pid: task.tid() as _,
                                si_uid: task.uid() as _,
                                ..Default::default()
                            }
                        }
                    }
                } else if let SigDetails::None = si.details {
                    log::error!("[sig_exec] SigDetail got None, do nothing",);
                    panic!("")
                } else {
                    log::error!(
                        "[sig_exec] SigDetail should be Kill, but got: {:?}",
                        si.details
                    );
                    panic!("sig_exec: unexpected siginfo details");
                };
                new_sp -= size_of::<LinuxSigInfo>();
                let mut siginfo_ptr = UserWritePtr::<LinuxSigInfo>::new(new_sp, &addr_space);
                unsafe { siginfo_ptr.write(siginfo)? };
                cx.set_user_a1(new_sp);
            }

            cx.sepc = entry;
            // ra (when the sigaction set by user finished,it will return to
            // _sigreturn_trampoline, which calls sys_sigreturn)
            cx.user_reg[1] = _sigreturn_trampoline as usize;
            // sp (it will be used later by sys_sigreturn to restore sig_cx)
            cx.set_user_sp(new_sp);

            #[cfg(target_arch = "riscv64")]
            {
                cx.user_reg[3] = sig_cx.user_reg[3];
                cx.user_reg[4] = sig_cx.user_reg[4];
            }
            #[cfg(target_arch = "loongarch64")]
            {
                assert!(cx.user_reg[2] == sig_cx.user_reg[2]);
                assert!(cx.user_reg[21] == sig_cx.user_reg[21]);
                assert!(cx.user_reg[28] == sig_cx.user_reg[28]);
            }

            // cx.user_reg
            //     .iter()
            //     .enumerate()

#![no_std]
#![no_main]
extern crate alloc;

use alloc::{boxed::Box, sync::Arc, task::Wake};
use core::{
    pin::Pin,
    task::{Context, Poll, Waker, ready},
};

/// `take_waker()` gets future waker in current context. when future temps to
/// be waken, it can call this waker to wake it up and rejoin
/// the hart queue.
#[inline(always)]
pub async fn take_waker() -> Waker {
    TakeWakerFuture.await
}

/// `TakeWakerFuture` is created just to assist to implement
/// Future trait and get waker from its context.
struct TakeWakerFuture;

impl Future for TakeWakerFuture {
    type Output = Waker;
    #[inline(always)]
    fn poll(self: Pin<&mut Self>, cx: &mut Context<'_>) -> Poll<Self::Output> {
        Poll::Ready(cx.waker().clone())
    }
}

/// `SuspendFuture` relinquishes the execution of the current task.
struct SuspendFuture {
    has_suspended: bool,
}

impl SuspendFuture {
    const fn new() -> Self {
        Self {
            has_suspended: false,
        }
    }
}

impl Future for SuspendFuture {
    type Output = ();

    /// Suspend logic:
    /// - The first poll returns Pending (triggers pending)
    /// - Subsequent polls return to Ready (Resume Execution)
    fn poll(mut self: Pin<&mut Self>, _cx: &mut Context) -> Poll<Self::Output> {
        match self.has_suspended {
            true => Poll::Ready(()),
            false => {
                self.has_suspended = true;
                Poll::Pending
            }
        }
    }
}

/// the caller task will suspend and give cpu to other tasks.
/// If the task temps to rejoin the hart TaskLine again, its
/// waker should be called by other tasks.
pub async fn suspend_now() {
    log::debug!("suspend");
    SuspendFuture::new().await
}

struct YieldFuture {
    has_yielded: bool,
}

impl YieldFuture {
    const fn new() -> Self {
        Self { has_yielded: false }
    }
}

impl Future for YieldFuture {
    type Output = ();

    fn poll(mut self: Pin<&mut Self>, cx: &mut Context) -> Poll<Self::Output> {
        match self.has_yielded {
            true => Poll::Ready(()),
            false => {
                self.has_yielded = true;
                cx.waker().wake_by_ref();
                Poll::Pending
            }
        }
    }
}

/// the caller task will suspend and give cpu to other tasks.
/// Unlike [`suspend_now()`], this function will call waker before
/// it is suspended. Therefore, it will join the end of the queue.
/// When the previous tasks are executed, it will run again.
pub async fn yield_now() {
    YieldFuture::new().await;
}

/// `BlockWaker` is a structure which implements Wake trait.
/// It means that this waker can be passed in context as a
/// waker and when it is called, it can act as its pre-set
/// action and not act by default.
struct BlockWaker;

impl Wake for BlockWaker {
    fn wake(self: Arc<Self>) {
        log::trace!("block waker wakes");
    }
}

/// Run a future to completion on the current thread.
/// Note that since this function is used in kernel mode,
/// we won't switch thread when the inner future pending.
/// Instead, we just poll the inner future again and again.
pub fn block_on<T>(fut: impl Future<Output = T>) -> T {
    // Pin the future so it can be polled.
    let mut fut = Box::pin(fut);

    let waker = Arc::new(BlockWaker).into();
    let mut cx = Context::from_waker(&waker);

    // Run the future to completion.
    loop {
        match fut.as_mut().poll(&mut cx) {
            Poll::Ready(res) => return res,
            Poll::Pending => continue,
        }
    }
}

/// Like [`block_on`], this function can wrap a async function in a sync function.
/// But different from `block_on`, it will loop for a certain number. If the async task can
/// return Ready during loop, it can return Ok. Otherwise, it will return Err.
pub fn block_on_with_result<T>(fut: impl Future<Output = T>) -> Result<T, ()> {
    // Pin the future so it can be polled.
    let mut fut = Box::pin(fut);
    let mut cnt = 0;

    let waker = Arc::new(BlockWaker).into();
    let mut cx = Context::from_waker(&waker);

    // Run the future to completion.
    loop {
        match fut.as_mut().poll(&mut cx) {
            Poll::Ready(res) => return Ok(res),
            Poll::Pending => {
                cnt += 1;
                if cnt > 10000 {
                    return Err(());
                }
                continue;
            }
        }
    }
}

pub enum SelectOutput<T1, T2> {
    Output1(T1),
    Output2(T2),
}

/// Select two futures at a time.
/// Note that future1 has a higher level than future2
pub struct Select2Futures<T1, T2, F1, F2>
where
    F1: Future<Output = T1>,
    F2: Future<Output = T2>,
{
    future1: F1,
    future2: F2,
}

impl<T1, T2, F1, F2> Select2Futures<T1, T2, F1, F2>
where
    F1: Future<Output = T1>,
    F2: Future<Output = T2>,
{
    pub fn new(future1: F1, future2: F2) -> Self {
        Self { future1, future2 }
    }
}

impl<T1, T2, F1, F2> Future for Select2Futures<T1, T2, F1, F2>
where
    F1: Future<Output = T1>,
    F2: Future<Output = T2>,
{
    type Output = SelectOutput<T1, T2>;
    fn poll(self: Pin<&mut Self>, cx: &mut Context<'_>) -> Poll<Self::Output> {
        let this = unsafe { self.get_unchecked_mut() };
        let ret = unsafe { Pin::new_unchecked(&mut this.future1).poll(cx) };
        if ret.is_ready() {
            return Poll::Ready(SelectOutput::Output1(ready!(ret)));
        }
        let ret = unsafe { Pin::new_unchecked(&mut this.future2).poll(cx) };
        if ret.is_ready() {
            return Poll::Ready(SelectOutput::Output2(ready!(ret)));
        }
        Poll::Pending
    }
}
